args.sparql:
SELECT ?year WHERE {
  ?film wdt:P31 wd:Q11424 ;
        wdt:P161 wd:Q580587 ;
        wdt:P577 ?date .
  ?film p:P161 ?statement .
  ?statement pq:P451 wd:Q723493 .
  BIND(YEAR(?date) AS ?year)
}

SELECT ?year WHERE {
  ?film wdt:P31 wd:Q11424 .
  ?film wdt:P161 wd:Q580587 .
  ?film p:P161 ?castStatement .
  ?castStatement ps:P161 wd:Q580587 ;
                 pq:P451 wd:Q723493 .
  ?film wdt:P577 ?releaseDate .
  BIND(YEAR(?releaseDate) AS ?year)
}
